NS="karma-rabbitmq-security-upgrade-lifec-8dfe1e47-cluster-a"

# Patch the StatefulSet to add the TLS volume and mount it
kubectl -n $NS patch statefulset rabbitmq --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "tls",
      "secret": {
        "secretName": "rabbitmq-tls",
        "items": [
          {"key": "ca.crt", "path": "ca.crt"},
          {"key": "tls.crt", "path": "tls.crt"},
          {"key": "tls.key", "path": "tls.key"}
        ]
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "tls",
      "mountPath": "/etc/rabbitmq/tls",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/ports/-",
    "value": {
      "containerPort": 5671,
      "name": "amqps"
    }
  }
]'
echo "StatefulSet patched with TLS volume mount"

NS="karma-rabbitmq-security-upgrade-lifec-8dfe1e47-cluster-a"

# Add AMQPS port to the service
kubectl -n $NS patch svc rabbitmq --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/ports/-",
    "value": {
      "name": "amqps",
      "port": 5671,
      "targetPort": 5671,
      "protocol": "TCP"
    }
  }
]'

kubectl -n $NS patch svc rabbitmq-headless --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/ports/-",
    "value": {
      "name": "amqps",
      "port": 5671,
      "targetPort": 5671,
      "protocol": "TCP"
    }
  }
]'
echo "Services updated with AMQPS port"
